def _get_executable_info(name):
    """
    Get the version of some executable that Matplotlib optionally depends on.

    .. warning::
       The list of executables that this function supports is set according to
       Matplotlib's internal needs, and may change without notice.

    Parameters
    ----------
    name : str
        The executable to query.  The following values are currently supported:
        "dvipng", "gs", "inkscape", "magick", "pdftops".  This list is subject
        to change without notice.

    Returns
    -------
    tuple
        A namedtuple with fields ``executable`` (`str`) and ``version``
        (`packaging.Version`, or ``None`` if the version cannot be determined).

    Raises
    ------
    ExecutableNotFoundError
        If the executable is not found or older than the oldest version
        supported by Matplotlib.
    ValueError
        If the executable is not one that we know how to query.
    """

    def impl(args, regex, min_ver=None, ignore_exit_code=False):
        # Execute the subprocess specified by args; capture stdout and stderr.
        # Search for a regex match in the output; if the match succeeds, the
        # first group of the match is the version.
        # Return an _ExecInfo if the executable exists, and has a version of
        # at least min_ver (if set); else, raise ExecutableNotFoundError.
        try:
            output = subprocess.check_output(
                args, stderr=subprocess.STDOUT,
                universal_newlines=True, errors="replace")
        except subprocess.CalledProcessError as _cpe:
            if ignore_exit_code:
                output = _cpe.output
            else:
                raise ExecutableNotFoundError(str(_cpe)) from _cpe
        except OSError as _ose:
            raise ExecutableNotFoundError(str(_ose)) from _ose
        match = re.search(regex, output)
        if match:
            version = parse_version(match.group(1))
            if min_ver is not None and version < parse_version(min_ver):
                raise ExecutableNotFoundError(
                    f"You have {args[0]} version {version} but the minimum "
                    f"version supported by Matplotlib is {min_ver}")
            return _ExecInfo(args[0], version)
        else:
            raise ExecutableNotFoundError(
                f"Failed to determine the version of {args[0]} from "
                f"{' '.join(args)}, which output {output}")

    if name == "dvipng":
        return impl(["dvipng", "-version"], "(?m)^dvipng(?: .*)? (.+)", "1.6")
    elif name == "gs":
        execs = (["gswin32c", "gswin64c", "mgs", "gs"]  # "mgs" for miktex.
                 if sys.platform == "win32" else
                 ["gs"])
        for e in execs:
            try:
                return impl([e, "--version"], "(.*)", "9")
            except ExecutableNotFoundError:
                pass
        message = "Failed to find a Ghostscript installation"
        raise ExecutableNotFoundError(message)
    elif name == "inkscape":
        try:
            # Try headless option first (needed for Inkscape version < 1.0):
            return impl(["inkscape", "--without-gui", "-V"],
                        "Inkscape ([^ ]*)")
        except ExecutableNotFoundError:
            pass  # Suppress exception chaining.
        # If --without-gui is not accepted, we may be using Inkscape >= 1.0 so
        # try without it:
        return impl(["inkscape", "-V"], "Inkscape ([^ ]*)")
    elif name == "magick":
        if sys.platform == "win32":
            # Check the registry to avoid confusing ImageMagick's convert with
            # Windows's builtin convert.exe.
            import winreg
            binpath = ""
            for flag in [0, winreg.KEY_WOW64_32KEY, winreg.KEY_WOW64_64KEY]:
                try:
                    with winreg.OpenKeyEx(
                            winreg.HKEY_LOCAL_MACHINE,
                            r"Software\Imagemagick\Current",
                            0, winreg.KEY_QUERY_VALUE | flag) as hkey:
                        binpath = winreg.QueryValueEx(hkey, "BinPath")[0]
                except OSError:
                    pass
            path = None
            if binpath:
                for name in ["convert.exe", "magick.exe"]:
                    candidate = Path(binpath, name)
                    if candidate.exists():
                        path = str(candidate)
                        break
            if path is None:
                raise ExecutableNotFoundError(
                    "Failed to find an ImageMagick installation")
        else:
            path = "convert"
        info = impl([path, "--version"], r"^Version: ImageMagick (\S*)")
        if info.version == parse_version("7.0.10-34"):
            # https://github.com/ImageMagick/ImageMagick/issues/2720
            raise ExecutableNotFoundError(
                f"You have ImageMagick {info.version}, which is unsupported")
        return info
    elif name == "pdftops":
        info = impl(["pdftops", "-v"], "^pdftops version (.*)",
                    ignore_exit_code=True)
        if info and not (
                3 <= info.version.major or
                # poppler version numbers.
                parse_version("0.9") <= info.version < parse_version("1.0")):
            raise ExecutableNotFoundError(
                f"You have pdftops version {info.version} but the minimum "
                f"version supported by Matplotlib is 3.0")
        return info
    else:
        raise ValueError("Unknown executable: {!r}".format(name))

def rc_params(fail_on_error=False):
    """Construct a `RcParams` instance from the default Matplotlib rc file."""
    return rc_params_from_file(matplotlib_fname(), fail_on_error)

def _get_ssl_context():
    try:
        import certifi
    except ImportError:
        _log.debug("Could not import certifi.")
        return None
    import ssl
    return ssl.create_default_context(cafile=certifi.where())

def get_data_path():
    """Return the path to Matplotlib data."""
    return str(Path(__file__).with_name("mpl-data"))

def format_coord(self, x, y):
    """Return a format string formatting the *x*, *y* coordinates."""
    return "x={} y={}".format(
        "???" if x is None else self.format_xdata(x),
        "???" if y is None else self.format_ydata(y),
    )

def inverse(self, value):
    if not self.scaled():
        raise ValueError("Not invertible until both vmin and vmax are set")
    (vmin,), _ = self.process_value(self.vmin)
    (vmax,), _ = self.process_value(self.vmax)

    if np.iterable(value):
        val = np.ma.asarray(value)
        return vmin + val * (vmax - vmin)
    else:
        return vmin + value * (vmax - vmin)

def destroy_fig(cls, fig):
    """Destroy figure *fig*."""
    num = next((manager.num for manager in cls.figs.values()
                if manager.canvas.figure == fig), None)
    if num is not None:
        cls.destroy(num)

def has_fignum(cls, num):
    """Return whether figure number *num* exists."""
    return num in cls.figs

def get_all_fig_managers(cls):
    """Return a list of figure managers."""
    return list(cls.figs.values())

def get_fig_manager(cls, num):
    """
    If manager number *num* exists, make it the active one and return it;
    otherwise return *None*.
    """
    manager = cls.figs.get(num, None)
    if manager is not None:
        cls.set_active(manager)
    return manager

def gcf():
    """
    Get the current figure.

    If there is currently no figure on the pyplot figure stack, a new one is
    created using `~.pyplot.figure()`.  (To test whether there is currently a
    figure on the pyplot figure stack, check whether `~.pyplot.get_fignums()`
    is empty.)
    """
    manager = _pylab_helpers.Gcf.get_active()
    if manager is not None:
        return manager.canvas.figure
    else:
        return figure()

def new_figure_manager(*args, **kwargs):
    """Create a new figure manager instance."""
    _warn_if_gui_out_of_main_thread()
    return _get_backend_mod().new_figure_manager(*args, **kwargs)

def new_figure_manager_given_figure(cls, num, figure):
    """Create a new figure manager instance for the given figure."""
    return cls.FigureCanvas.new_manager(figure, num)

def get_transformed_clip_path_and_affine(self):
    """
    Return the clip path with the non-affine part of its
    transformation applied, and the remaining affine part of its
    transformation.
    """
    if self._clippath is not None:
        return self._clippath.get_transformed_path_and_affine()
    return None, None

def _get_transformed_path(self):
    """Return this line's `~matplotlib.transforms.TransformedPath`."""
    if self._transformed_path is None:
        self._transform_path()
    return self._transformed_path

def _is_sorted(self, x):
    """Return whether x is sorted in ascending order."""
    # We don't handle the monotonically decreasing case.
    return _path.is_sorted(x)

def _get_markerfacecolor(self, alt=False):
    if self._marker.get_fillstyle() == 'none':
        return 'none'
    fc = self._markerfacecoloralt if alt else self._markerfacecolor
    if cbook._str_lower_equal(fc, 'auto'):
        return self._color
    else:
        return fc

def get_data(self, orig=True):
    """
    Return the line data as an ``(xdata, ydata)`` pair.

    If *orig* is *True*, return the original data.
    """
    return self.get_xdata(orig=orig), self.get_ydata(orig=orig)

def get_constrained_layout(self):
    """
    Return whether constrained layout is being used.

    See :doc:`/tutorials/intermediate/constrainedlayout_guide`.
    """
    return isinstance(self.get_layout_engine(), ConstrainedLayoutEngine)

def get_subplotspec_list(axes_list, grid_spec=None):
    """
    Return a list of subplotspec from the given list of axes.

    For an instance of axes that does not support subplotspec, None is inserted
    in the list.

    If grid_spec is given, None is inserted for those not from the given
    grid_spec.
    """
    subplotspec_list = []
    for ax in axes_list:
        axes_or_locator = ax.get_axes_locator()
        if axes_or_locator is None:
            axes_or_locator = ax

        if hasattr(axes_or_locator, "get_subplotspec"):
            subplotspec = axes_or_locator.get_subplotspec()
            if subplotspec is not None:
                subplotspec = subplotspec.get_topmost_subplotspec()
                gs = subplotspec.get_gridspec()
                if grid_spec is not None:
                    if gs != grid_spec:
                        subplotspec = None
                elif gs.locally_modified_subplot_params():
                    subplotspec = None
        else:
            subplotspec = None

        subplotspec_list.append(subplotspec)

    return subplotspec_list

def _safe_first_finite(obj, *, skip_nonfinite=True):
    """
    Return the first non-None (and optionally finite) element in *obj*.

    This is a method for internal use.

    This is an type-independent way of obtaining the first non-None element,
    supporting both index access and the iterator protocol.
    The first non-None element will be obtained when skip_none is True.
    """
    def safe_isfinite(val):
        if val is None:
            return False
        try:
            return np.isfinite(val) if np.isscalar(val) else True
        except TypeError:
            # This is something that numpy can not make heads or tails
            # of, assume "finite"
            return True
    if skip_nonfinite is False:
        if isinstance(obj, collections.abc.Iterator):
            # needed to accept `array.flat` as input.
            # np.flatiter reports as an instance of collections.Iterator
            # but can still be indexed via [].
            # This has the side effect of re-setting the iterator, but
            # that is acceptable.
            try:
                return obj[0]
            except TypeError:
                pass
            raise RuntimeError("matplotlib does not support generators "
                               "as input")
        return next(iter(obj))
    elif isinstance(obj, np.flatiter):
        # TODO do the finite filtering on this
        return obj[0]
    elif isinstance(obj, collections.abc.Iterator):
        raise RuntimeError("matplotlib does not "
                           "support generators as input")
    else:
        return next(val for val in obj if safe_isfinite(val))

def _preprocess_data(func=None, *, replace_names=None, label_namer=None):
    """
    A decorator to add a 'data' kwarg to a function.

    When applied::

        @_preprocess_data()
        def func(ax, *args, **kwargs): ...

    the signature is modified to ``decorated(ax, *args, data=None, **kwargs)``
    with the following behavior:

    - if called with ``data=None``, forward the other arguments to ``func``;
    - otherwise, *data* must be a mapping; for any argument passed in as a
      string ``name``, replace the argument by ``data[name]`` (if this does not
      throw an exception), then forward the arguments to ``func``.

    In either case, any argument that is a `MappingView` is also converted to a
    list.

    Parameters
    ----------
    replace_names : list of str or None, default: None
        The list of parameter names for which lookup into *data* should be
        attempted. If None, replacement is attempted for all arguments.
    label_namer : str, default: None
        If set e.g. to "namer" (which must be a kwarg in the function's
        signature -- not as ``**kwargs``), if the *namer* argument passed in is
        a (string) key of *data* and no *label* kwarg is passed, then use the
        (string) value of the *namer* as *label*. ::

            @_preprocess_data(label_namer="foo")
            def func(foo, label=None): ...

            func("key", data={"key": value})
            # is equivalent to
            func.__wrapped__(value, label="key")
    """

    if func is None:  # Return the actual decorator.
        return functools.partial(
            _preprocess_data,
            replace_names=replace_names, label_namer=label_namer)

    sig = inspect.signature(func)
    varargs_name = None
    varkwargs_name = None
    arg_names = []
    params = list(sig.parameters.values())
    for p in params:
        if p.kind is Parameter.VAR_POSITIONAL:
            varargs_name = p.name
        elif p.kind is Parameter.VAR_KEYWORD:
            varkwargs_name = p.name
        else:
            arg_names.append(p.name)
    data_param = Parameter("data", Parameter.KEYWORD_ONLY, default=None)
    if varkwargs_name:
        params.insert(-1, data_param)
    else:
        params.append(data_param)
    new_sig = sig.replace(parameters=params)
    arg_names = arg_names[1:]  # remove the first "ax" / self arg

    assert {*arg_names}.issuperset(replace_names or []) or varkwargs_name, (
        "Matplotlib internal error: invalid replace_names ({!r}) for {!r}"
        .format(replace_names, func.__name__))
    assert label_namer is None or label_namer in arg_names, (
        "Matplotlib internal error: invalid label_namer ({!r}) for {!r}"
        .format(label_namer, func.__name__))

    @functools.wraps(func)
    def inner(ax, *args, data=None, **kwargs):
        if data is None:
            return func(ax, *map(sanitize_sequence, args), **kwargs)

        bound = new_sig.bind(ax, *args, **kwargs)
        auto_label = (bound.arguments.get(label_namer)
                      or bound.kwargs.get(label_namer))

        for k, v in bound.arguments.items():
            if k == varkwargs_name:
                for k1, v1 in v.items():
                    if replace_names is None or k1 in replace_names:
                        v[k1] = _replacer(data, v1)
            elif k == varargs_name:
                if replace_names is None:
                    bound.arguments[k] = tuple(_replacer(data, v1) for v1 in v)
            else:
                if replace_names is None or k in replace_names:
                    bound.arguments[k] = _replacer(data, v)

        new_args = bound.args
        new_kwargs = bound.kwargs

        args_and_kwargs = {**bound.arguments, **bound.kwargs}
        if label_namer and "label" not in args_and_kwargs:
            new_kwargs["label"] = _label_from_arg(
                args_and_kwargs.get(label_namer), auto_label)

        return func(*new_args, **new_kwargs)

    inner.__doc__ = _add_data_doc(inner.__doc__, replace_names)
    inner.__signature__ = new_sig
    return inner

def inner(ax, *args, data=None, **kwargs):
    if data is None:
        return func(ax, *map(sanitize_sequence, args), **kwargs)

    bound = new_sig.bind(ax, *args, **kwargs)
    auto_label = (bound.arguments.get(label_namer)
                  or bound.kwargs.get(label_namer))

    for k, v in bound.arguments.items():
        if k == varkwargs_name:
            for k1, v1 in v.items():
                if replace_names is None or k1 in replace_names:
                    v[k1] = _replacer(data, v1)
        elif k == varargs_name:
            if replace_names is None:
                bound.arguments[k] = tuple(_replacer(data, v1) for v1 in v)
        else:
            if replace_names is None or k in replace_names:
                bound.arguments[k] = _replacer(data, v)

    new_args = bound.args
    new_kwargs = bound.kwargs

    args_and_kwargs = {**bound.arguments, **bound.kwargs}
    if label_namer and "label" not in args_and_kwargs:
        new_kwargs["label"] = _label_from_arg(
            args_and_kwargs.get(label_namer), auto_label)

    return func(*new_args, **new_kwargs)

def bar(
        x, height, width=0.8, bottom=None, *, align='center',
        data=None, **kwargs):
    return gca().bar(
        x, height, width=width, bottom=bottom, align=align,
        **({"data": data} if data is not None else {}), **kwargs)

def _convert_path(self, path, transform, clip=False, simplify=None):
    if clip:
        clip = (0.0, 0.0, self.width * 72.0, self.height * 72.0)
    else:
        clip = None
    return _path.convert_to_string(
        path, transform, clip, simplify, None,
        6, [b"m", b"l", b"", b"c", b"cl"], True).decode("ascii")

def iter_user_libraries():
    for stylelib_path in USER_LIBRARY_PATHS:
        stylelib_path = os.path.expanduser(stylelib_path)
        if os.path.exists(stylelib_path) and os.path.isdir(stylelib_path):
            yield stylelib_path

def update_user_library(library):
    """Update style library with user-defined rc files."""
    for stylelib_path in map(os.path.expanduser, USER_LIBRARY_PATHS):
        styles = read_style_directory(stylelib_path)
        update_nested_dict(library, styles)
    return library

def read_style_directory(style_dir):
    """Return dictionary of styles defined in *style_dir*."""
    styles = dict()
    for path in Path(style_dir).glob(f"*.{STYLE_EXTENSION}"):
        with warnings.catch_warnings(record=True) as warns:
            styles[path.stem] = rc_params_from_file(
                path, use_default_template=False)
        for w in warns:
            _log.warning('In %s: %s', path, w.message)
    return styles

def _remove_blacklisted_style_params(d, warn=True):
    o = {}
    for key in d:  # prevent triggering RcParams.__getitem__('backend')
        if key in STYLE_BLACKLIST:
            if warn:
                _api.warn_external(
                    f"Style includes a parameter, {key!r}, that is not "
                    "related to style.  Ignoring this parameter.")
        else:
            o[key] = d[key]
    return o

def _value_in_bounds(self, vals):
    """Clip min, max values to the bounds."""
    return (self._min_in_bounds(vals[0]), self._max_in_bounds(vals[1]))

def _min_in_bounds(self, min):
    """Ensure the new min value is between valmin and self.val[1]."""
    if min <= self.valmin:
        if not self.closedmin:
            return self.val[0]
        min = self.valmin

    if min > self.val[1]:
        min = self.val[1]
    return self._stepped_value(min)

def _max_in_bounds(self, max):
    """Ensure the new max value is between valmax and self.val[0]."""
    if max >= self.valmax:
        if not self.closedmax:
            return self.val[1]
        max = self.valmax

    if max <= self.val[0]:
        max = self.val[0]
    return self._stepped_value(max)

def _update_val_from_pos(self, pos):
    """Update the slider value based on a given position."""
    idx = np.argmin(np.abs(self.val - pos))
    if idx == 0:
        val = self._min_in_bounds(pos)
        self.set_min(val)
    else:
        val = self._max_in_bounds(pos)
        self.set_max(val)
    if self._active_handle:
        self._active_handle.set_xdata([val])

def get_rotation(rotation):
    """
    Return *rotation* normalized to an angle between 0 and 360 degrees.

    Parameters
    ----------
    rotation : float or {None, 'horizontal', 'vertical'}
        Rotation angle in degrees. *None* and 'horizontal' equal 0,
        'vertical' equals 90.

    Returns
    -------
    float
    """
    try:
        return float(rotation) % 360
    except (ValueError, TypeError) as err:
        if cbook._str_equal(rotation, 'horizontal') or rotation is None:
            return 0.
        elif cbook._str_equal(rotation, 'vertical'):
            return 90.
        else:
            raise ValueError("rotation is {!r}; expected either 'horizontal', "
                             "'vertical', numeric value, or None"
                             .format(rotation)) from err

def _set_tick_locations(self, ticks, *, minor=False):
    # see docstring of set_ticks

    # XXX if the user changes units, the information will be lost here
    ticks = self.convert_units(ticks)
    for name, axis in self.axes._axis_map.items():
        if self is axis:
            shared = [
                getattr(ax, f"{name}axis")
                for ax
                in self.axes._shared_axes[name].get_siblings(self.axes)]
            break
    else:
        shared = [self]
    if len(ticks):
        for axis in shared:
            # set_view_interval maintains any preexisting inversion.
            axis.set_view_interval(min(ticks), max(ticks))
    self.axes.stale = True
    if minor:
        self.set_minor_locator(mticker.FixedLocator(ticks))
        return self.get_minor_ticks(len(ticks))
    else:
        self.set_major_locator(mticker.FixedLocator(ticks))
        return self.get_major_ticks(len(ticks))

def resampled(self, lutsize):
    """Return a new colormap with *lutsize* entries."""
    if hasattr(self, '_resample'):
        _api.warn_external(
            "The ability to resample a color map is now public API "
            f"However the class {type(self)} still only implements "
            "the previous private _resample method.  Please update "
            "your class."
        )
        return self._resample(lutsize)

    raise NotImplementedError()

def copy(self):
    """Return a copy of the colormap."""
    return self.__copy__()

def get_bad(self):
    """Get the color for masked values."""
    if not self._isinit:
        self._init()
    return np.array(self._lut[self._i_bad])

def get_under(self):
    """Get the color for low out-of-range values."""
    if not self._isinit:
        self._init()
    return np.array(self._lut[self._i_under])

def get_over(self):
    """Get the color for high out-of-range values."""
    if not self._isinit:
        self._init()
    return np.array(self._lut[self._i_over])

def set_extremes(self, *, bad=None, under=None, over=None):
    """
    Set the colors for masked (*bad*) values and, when ``norm.clip =
    False``, low (*under*) and high (*over*) out-of-range values.
    """
    if bad is not None:
        self.set_bad(bad)
    if under is not None:
        self.set_under(under)
    if over is not None:
        self.set_over(over)

def flush_events(self):
    # docstring inherited
    QtWidgets.QApplication.instance().processEvents()

def _draw_idle(self):
    with self._idle_draw_cntx():
        if not self._draw_pending:
            return
        self._draw_pending = False
        if self.height() < 0 or self.width() < 0:
            return
        try:
            self.draw()
        except Exception:
            # Uncaught exceptions are fatal for PyQt5, so catch them.
            traceback.print_exc()

def _get_draw_artists(self, renderer):
    """Also runs apply_aspect"""
    artists = self.get_children()
    for sfig in self.subfigs:
        artists.remove(sfig)
        childa = sfig.get_children()
        for child in childa:
            if child in artists:
                artists.remove(child)

    artists.remove(self.patch)
    artists = sorted(
        (artist for artist in artists if not artist.get_animated()),
        key=lambda artist: artist.get_zorder())
    for ax in self._localaxes:
        locator = ax.get_axes_locator()
        ax.apply_aspect(locator(ax, renderer) if locator else None)

        for child in ax.get_children():
            if hasattr(child, 'apply_aspect'):
                locator = child.get_axes_locator()
                child.apply_aspect(
                    locator(child, renderer) if locator else None)
    return artists

def _set_facecolor(self, c):
    if c is None:
        c = self._get_default_facecolor()

    self._facecolors = mcolors.to_rgba_array(c, self._alpha)
    self.stale = True

def _get_default_facecolor(self):
    # This may be overridden in a subclass.
    return mpl.rcParams['patch.facecolor']

def clf():
    """Clear the current figure."""
    gcf().clear()

def draw(self, renderer):
    # docstring inherited

    # draw the figure bounding box, perhaps none for white figure
    if not self.get_visible():
        return

    artists = self._get_draw_artists(renderer)
    try:
        renderer.open_group('figure', gid=self.get_gid())
        if self.axes and self.get_layout_engine() is not None:
            try:
