    else:
        axes_vars = [x_var, y_var]

    if self._hue_var is not None and self._hue_var not in axes_vars:
        axes_vars.append(self._hue_var)

    data = self.data[axes_vars]
    if self._dropna:
        data = data.dropna()

    x = data[x_var]
    y = data[y_var]
    if self._hue_var is None:
        hue = None
    else:
        hue = data.get(self._hue_var)

    if "hue" not in kwargs:
        kwargs.update({
            "hue": hue, "hue_order": self._hue_order, "palette": self._orig_palette,
        })
    func(x=x, y=y, **kwargs)

    self._update_legend_data(ax)

def _plot_bivariate_iter_hue(self, x_var, y_var, ax, func, **kwargs):
    """Draw a bivariate plot while iterating over hue subsets."""
    kwargs = kwargs.copy()
    if str(func.__module__).startswith("seaborn"):
        kwargs["ax"] = ax
    else:
        plt.sca(ax)

    if x_var == y_var:
        axes_vars = [x_var]
    else:
        axes_vars = [x_var, y_var]

    hue_grouped = self.data.groupby(self.hue_vals)
    for k, label_k in enumerate(self._hue_order):

        kws = kwargs.copy()

        # Attempt to get data for this level, allowing for empty
        try:
            data_k = hue_grouped.get_group(label_k)
        except KeyError:
            data_k = pd.DataFrame(columns=axes_vars,
                                  dtype=float)

        if self._dropna:
            data_k = data_k[axes_vars].dropna()

        x = data_k[x_var]
        y = data_k[y_var]

        for kw, val_list in self.hue_kws.items():
            kws[kw] = val_list[k]
        kws.setdefault("color", self.palette[k])
        if self._hue_var is not None:
            kws["label"] = label_k

        if str(func.__module__).startswith("seaborn"):
            func(x=x, y=y, **kws)
        else:
            func(x, y, **kws)

    self._update_legend_data(ax)

def _add_axis_labels(self):
    """Add labels to the left and bottom Axes."""
    for ax, label in zip(self.axes[-1, :], self.x_vars):
        ax.set_xlabel(label)
    for ax, label in zip(self.axes[:, 0], self.y_vars):
        ax.set_ylabel(label)

def get_var(var):
    vector = plot_data.get(var, None)
    if vector is not None:
        vector = vector.rename(p.variables.get(var, None))
    return vector

def _find_numeric_cols(self, data):
    """Find which variables in a DataFrame are numeric."""
    numeric_cols = []
    for col in data:
        if variable_type(data[col]) == "numeric":
            numeric_cols.append(col)
    return numeric_cols

def variable_type(vector, boolean_type="numeric"):
    """
    Determine whether a vector contains numeric, categorical, or datetime data.

    This function differs from the pandas typing API in two ways:

    - Python sequences or object-typed PyData objects are considered numeric if
      all of their entries are numeric.
    - String or mixed-type data are considered categorical even if not
      explicitly represented as a :class:`pandas.api.types.CategoricalDtype`.

    Parameters
    ----------
    vector : :func:`pandas.Series`, :func:`numpy.ndarray`, or Python sequence
        Input data to test.
    boolean_type : 'numeric' or 'categorical'
        Type to use for vectors containing only 0s and 1s (and NAs).

    Returns
    -------
    var_type : 'numeric', 'categorical', or 'datetime'
        Name identifying the type of data in the vector.
    """
    vector = pd.Series(vector)

    # If a categorical dtype is set, infer categorical
    if isinstance(vector.dtype, pd.CategoricalDtype):
        return VariableType("categorical")

    # Special-case all-na data, which is always "numeric"
    if pd.isna(vector).all():
        return VariableType("numeric")

    # At this point, drop nans to simplify further type inference
    vector = vector.dropna()

    # Special-case binary/boolean data, allow caller to determine
    # This triggers a numpy warning when vector has strings/objects
    # https://github.com/numpy/numpy/issues/6784
    # Because we reduce with .all(), we are agnostic about whether the
    # comparison returns a scalar or vector, so we will ignore the warning.
    # It triggers a separate DeprecationWarning when the vector has datetimes:
    # https://github.com/numpy/numpy/issues/13548
    # This is considered a bug by numpy and will likely go away.
    with warnings.catch_warnings():
        warnings.simplefilter(
            action='ignore', category=(FutureWarning, DeprecationWarning)
        )
        if np.isin(vector, [0, 1]).all():
            return VariableType(boolean_type)

    # Defer to positive pandas tests
    if pd.api.types.is_numeric_dtype(vector):
        return VariableType("numeric")

    if pd.api.types.is_datetime64_dtype(vector):
        return VariableType("datetime")

    # --- If we get to here, we need to check the entries

    # Check for a collection where everything is a number

    def all_numeric(x):
        for x_i in x:
            if not isinstance(x_i, Number):
                return False
        return True

    if all_numeric(vector):
        return VariableType("numeric")

    # Check for a collection where everything is a datetime

    def all_datetime(x):
        for x_i in x:
            if not isinstance(x_i, (datetime, np.datetime64)):
                return False
        return True

    if all_datetime(vector):
        return VariableType("datetime")

    # Otherwise, our final fallback is to consider things categorical

    return VariableType("categorical")

def register(self, app: "Flask", options: dict) -> None:
    """Called by :meth:`Flask.register_blueprint` to register all
    views and callbacks registered on the blueprint with the
    application. Creates a :class:`.BlueprintSetupState` and calls
    each :meth:`record` callbackwith it.

    :param app: The application this blueprint is being registered
        with.
    :param options: Keyword arguments forwarded from
        :meth:`~Flask.register_blueprint`.
    :param first_registration: Whether this is the first time this
        blueprint has been registered on the application.
    """
    first_registration = False

    if self.name in app.blueprints:
        assert app.blueprints[self.name] is self, (
            "A name collision occurred between blueprints"
            f" {self!r} and {app.blueprints[self.name]!r}."
            f" Both share the same name {self.name!r}."
            f" Blueprints that are created on the fly need unique"
            f" names."
        )
    else:
        app.blueprints[self.name] = self
        first_registration = True

    self._got_registered_once = True
    state = self.make_setup_state(app, options, first_registration)

    if self.has_static_folder:
        state.add_url_rule(
            f"{self.static_url_path}/<path:filename>",
            view_func=self.send_static_file,
            endpoint="static",
        )

    # Merge blueprint data into parent.
    if first_registration:

        def extend(bp_dict, parent_dict):
            for key, values in bp_dict.items():
                key = self.name if key is None else f"{self.name}.{key}"

                parent_dict[key].extend(values)

        for key, value in self.error_handler_spec.items():
            key = self.name if key is None else f"{self.name}.{key}"
            value = defaultdict(
                dict,
                {
                    code: {
                        exc_class: func for exc_class, func in code_values.items()
                    }
                    for code, code_values in value.items()
                },
            )
            app.error_handler_spec[key] = value

        for endpoint, func in self.view_functions.items():
            app.view_functions[endpoint] = func

        extend(self.before_request_funcs, app.before_request_funcs)
        extend(self.after_request_funcs, app.after_request_funcs)
        extend(
            self.teardown_request_funcs,
            app.teardown_request_funcs,
        )
        extend(self.url_default_functions, app.url_default_functions)
        extend(self.url_value_preprocessors, app.url_value_preprocessors)
        extend(self.template_context_processors, app.template_context_processors)

    for deferred in self.deferred_functions:
        deferred(state)

    cli_resolved_group = options.get("cli_group", self.cli_group)

    if self.cli.commands:
        if cli_resolved_group is None:
            app.cli.commands.update(self.cli.commands)
        elif cli_resolved_group is _sentinel:
            self.cli.name = self.name
            app.cli.add_command(self.cli)
        else:
            self.cli.name = cli_resolved_group
            app.cli.add_command(self.cli)

    for blueprint, bp_options in self._blueprints:
        url_prefix = options.get("url_prefix", "")
        if "url_prefix" in bp_options:
            url_prefix = (
                url_prefix.rstrip("/") + "/" + bp_options["url_prefix"].lstrip("/")
            )

        bp_options["url_prefix"] = url_prefix
        bp_options["name_prefix"] = options.get("name_prefix", "") + self.name + "."
        blueprint.register(app, bp_options)

def make_setup_state(
    self, app: "Flask", options: dict, first_registration: bool = False
) -> BlueprintSetupState:
    """Creates an instance of :meth:`~flask.blueprints.BlueprintSetupState`
    object that is later passed to the register callback functions.
    Subclasses can override this to return a subclass of the setup state.
    """
    return BlueprintSetupState(self, app, options, first_registration)

def add_url_rule(
    self,
    rule: str,
    endpoint: t.Optional[str] = None,
    view_func: t.Optional[t.Callable] = None,
    provide_automatic_options: t.Optional[bool] = None,
    **options: t.Any,
) -> None:
    if endpoint is None:
        endpoint = _endpoint_from_view_func(view_func)  # type: ignore
    options["endpoint"] = endpoint
    methods = options.pop("methods", None)

    # if the methods are not given and the view_func object knows its
    # methods we can use that instead.  If neither exists, we go with
    # a tuple of only ``GET`` as default.
    if methods is None:
        methods = getattr(view_func, "methods", None) or ("GET",)
    if isinstance(methods, str):
        raise TypeError(
            "Allowed methods must be a list of strings, for"
            ' example: @app.route(..., methods=["POST"])'
        )
    methods = {item.upper() for item in methods}

    # Methods that should always be added
    required_methods = set(getattr(view_func, "required_methods", ()))

    # starting with Flask 0.8 the view_func object can disable and
    # force-enable the automatic options handling.
    if provide_automatic_options is None:
        provide_automatic_options = getattr(
            view_func, "provide_automatic_options", None
        )

    if provide_automatic_options is None:
        if "OPTIONS" not in methods:
            provide_automatic_options = True
            required_methods.add("OPTIONS")
        else:
            provide_automatic_options = False

    # Add the required methods now.
    methods |= required_methods

    rule = self.url_rule_class(rule, methods=methods, **options)
    rule.provide_automatic_options = provide_automatic_options  # type: ignore

    self.url_map.add(rule)
    if view_func is not None:
        old_func = self.view_functions.get(endpoint)
        if old_func is not None and old_func != view_func:
            raise AssertionError(
                "View function mapping is overwriting an existing"
                f" endpoint function: {endpoint}"
            )
        self.view_functions[endpoint] = view_func

def __init__(self, root_path: str, defaults: t.Optional[dict] = None) -> None:
    super().__init__(defaults or {})
    self.root_path = root_path

def from_mapping(
    self, mapping: t.Optional[t.Mapping[str, t.Any]] = None, **kwargs: t.Any
) -> bool:
    """Updates the config like :meth:`update` ignoring items with
    non-upper keys.

    :return: Always returns ``True``.

    .. versionadded:: 0.11
    """
    mappings: t.Dict[str, t.Any] = {}
    if mapping is not None:
        mappings.update(mapping)
    mappings.update(kwargs)
    for key, value in mappings.items():
        if key.isupper():
            self[key] = value
    return True

