def process_documenter_options(documenter: Type[Documenter], config: Config, options: Dict
                               ) -> Options:
    """Recognize options of Documenter from user input."""
    for name in AUTODOC_DEFAULT_OPTIONS:
        if name not in documenter.option_spec:
            continue
        else:
            negated = options.pop('no-' + name, True) is None
            if name in config.autodoc_default_options and not negated:
                if name in options and isinstance(config.autodoc_default_options[name], str):
                    # take value from options if present or extend it
                    # with autodoc_default_options if necessary
                    if name in AUTODOC_EXTENDABLE_OPTIONS:
                        if options[name] is not None and options[name].startswith('+'):
                            options[name] = ','.join([config.autodoc_default_options[name],
                                                      options[name][1:]])
                else:
                    options[name] = config.autodoc_default_options[name]

            elif options.get(name) is not None:
                # remove '+' from option argument if there's nothing to merge it with
                options[name] = options[name].lstrip('+')

    return Options(assemble_option_dict(options.items(), documenter.option_spec))

def get_object_members(self, want_all: bool) -> Tuple[bool, ObjectMembers]:
    members = get_class_members(self.object, self.objpath, self.get_attr)
    if not want_all:
        if not self.options.members:
            return False, []  # type: ignore
        # specific members given
        selected = []
        for name in self.options.members:  # type: str
            if name in members:
                selected.append(members[name])
            else:
                logger.warning(__('missing attribute %s in object %s') %
                               (name, self.fullname), type='autodoc')
        return False, selected
    elif self.options.inherited_members:
        return False, list(members.values())
    else:
        return False, [m for m in members.values() if m.class_ == self.object]

def inherited_members_option(arg: Any) -> Union[object, Set[str]]:
    """Used to convert the :members: option to auto directives."""
    if arg in (None, True):
        return 'object'
    else:
        return arg

def is_filtered_inherited_member(name: str, obj: Any) -> bool:
    if inspect.isclass(self.object):
        for cls in self.object.__mro__:
            if cls.__name__ == self.options.inherited_members and cls != self.object:
                # given member is a member of specified *super class*
                return True
            elif name in cls.__dict__:
                return False
            elif name in self.get_attr(cls, '__annotations__', {}):
                return False
            elif isinstance(obj, ObjectMember) and obj.class_ is cls:
                return False

    return False

def get_class_members(subject: Any, objpath: List[str], attrgetter: Callable
                      ) -> Dict[str, "ObjectMember"]:
    """Get members and attributes of target class."""
    from sphinx.ext.autodoc import INSTANCEATTR, ObjectMember

    # the members directly defined in the class
    obj_dict = attrgetter(subject, '__dict__', {})

    members: Dict[str, ObjectMember] = {}

    # enum members
    if isenumclass(subject):
        for name, value in subject.__members__.items():
            if name not in members:
                members[name] = ObjectMember(name, value, class_=subject)

        superclass = subject.__mro__[1]
        for name in obj_dict:
            if name not in superclass.__dict__:
                value = safe_getattr(subject, name)
                members[name] = ObjectMember(name, value, class_=subject)

    # members in __slots__
    try:
        __slots__ = getslots(subject)
        if __slots__:
            from sphinx.ext.autodoc import SLOTSATTR

            for name, docstring in __slots__.items():
                members[name] = ObjectMember(name, SLOTSATTR, class_=subject,
                                             docstring=docstring)
    except (TypeError, ValueError):
        pass

    # other members
    for name in dir(subject):
        try:
            value = attrgetter(subject, name)
            if ismock(value):
                value = undecorate(value)

            unmangled = unmangle(subject, name)
            if unmangled and unmangled not in members:
                if name in obj_dict:
                    members[unmangled] = ObjectMember(unmangled, value, class_=subject)
                else:
                    members[unmangled] = ObjectMember(unmangled, value)
        except AttributeError:
            continue

    try:
        for cls in getmro(subject):
            try:
                modname = safe_getattr(cls, '__module__')
                qualname = safe_getattr(cls, '__qualname__')
                analyzer = ModuleAnalyzer.for_module(modname)
                analyzer.analyze()
            except AttributeError:
                qualname = None
                analyzer = None
            except PycodeError:
                analyzer = None

            # annotation only member (ex. attr: int)
            for name in getannotations(cls):
                name = unmangle(cls, name)
                if name and name not in members:
                    if analyzer and (qualname, name) in analyzer.attr_docs:
                        docstring = '\n'.join(analyzer.attr_docs[qualname, name])
                    else:
                        docstring = None

                    members[name] = ObjectMember(name, INSTANCEATTR, class_=cls,
                                                 docstring=docstring)

            # append instance attributes (cf. self.attr1) if analyzer knows
            if analyzer:
                for (ns, name), docstring in analyzer.attr_docs.items():
                    if ns == qualname and name not in members:
                        members[name] = ObjectMember(name, INSTANCEATTR, class_=cls,
                                                     docstring='\n'.join(docstring))
    except AttributeError:
        pass

    return members

def getmro(obj: Any) -> Tuple[Type, ...]:
    """Get __mro__ from given *obj* safely."""
    __mro__ = safe_getattr(obj, '__mro__', None)
    if isinstance(__mro__, tuple):
        return __mro__
    else:
        return tuple()

def getorigbases(obj: Any) -> Optional[Tuple[Any, ...]]:
    """Get __orig_bases__ from *obj* safely."""
    if not inspect.isclass(obj):
        return None

    # Get __orig_bases__ from obj.__dict__ to avoid accessing the parent's __orig_bases__.
    # refs: https://github.com/sphinx-doc/sphinx/issues/9607
    __dict__ = safe_getattr(obj, '__dict__', {})
    __orig_bases__ = __dict__.get('__orig_bases__')
    if isinstance(__orig_bases__, tuple) and len(__orig_bases__) > 0:
        return __orig_bases__
    else:
        return None

def import_module(modname: str, warningiserror: bool = False) -> Any:
    """
    Call importlib.import_module(modname), convert exceptions to ImportError
    """
    try:
        with warnings.catch_warnings():
            warnings.filterwarnings("ignore", category=ImportWarning)
            with logging.skip_warningiserror(not warningiserror):
                return importlib.import_module(modname)
    except BaseException as exc:
        # Importing modules may cause any side effects, including
        # SystemExit, so we need to catch all errors.
        raise ImportError(exc, traceback.format_exc()) from exc

def import_object(modname: str, objpath: List[str], objtype: str = '',
                  attrgetter: Callable[[Any, str], Any] = safe_getattr,
                  warningiserror: bool = False) -> Any:
    if objpath:
        logger.debug('[autodoc] from %s import %s', modname, '.'.join(objpath))
    else:
        logger.debug('[autodoc] import %s', modname)

    try:
        module = None
        exc_on_importing = None
        objpath = list(objpath)
        while module is None:
            try:
                module = import_module(modname, warningiserror=warningiserror)
                logger.debug('[autodoc] import %s => %r', modname, module)
            except ImportError as exc:
                logger.debug('[autodoc] import %s => failed', modname)
                exc_on_importing = exc
                if '.' in modname:
                    # retry with parent module
                    modname, name = modname.rsplit('.', 1)
                    objpath.insert(0, name)
                else:
                    raise

        obj = module
        parent = None
        object_name = None
        for attrname in objpath:
            parent = obj
            logger.debug('[autodoc] getattr(_, %r)', attrname)
            mangled_name = mangle(obj, attrname)
            obj = attrgetter(obj, mangled_name)

            try:
                logger.debug('[autodoc] => %r', obj)
            except TypeError:
                # fallback of failure on logging for broken object
                # refs: https://github.com/sphinx-doc/sphinx/issues/9095
                logger.debug('[autodoc] => %r', (obj,))

            object_name = attrname
        return [module, parent, object_name, obj]
    except (AttributeError, ImportError) as exc:
        if isinstance(exc, AttributeError) and exc_on_importing:
            # restore ImportError
            exc = exc_on_importing

        if objpath:
            errmsg = ('autodoc: failed to import %s %r from module %r' %
                      (objtype, '.'.join(objpath), modname))
        else:
            errmsg = 'autodoc: failed to import %s %r' % (objtype, modname)

        if isinstance(exc, ImportError):
            # import_module() raises ImportError having real exception obj and
            # traceback
            real_exc, traceback_msg = exc.args
            if isinstance(real_exc, SystemExit):
                errmsg += ('; the module executes module level statement '
                           'and it might call sys.exit().')
            elif isinstance(real_exc, ImportError) and real_exc.args:
                errmsg += '; the following exception was raised:\n%s' % real_exc.args[0]
            else:
                errmsg += '; the following exception was raised:\n%s' % traceback_msg
        else:
            errmsg += '; the following exception was raised:\n%s' % traceback.format_exc()

        logger.debug(errmsg)
        raise ImportError(errmsg) from exc

def format_args(self, **kwargs: Any) -> str:
    if self.config.autodoc_typehints in ('none', 'description'):
        kwargs.setdefault('show_annotation', False)
    if self.config.autodoc_typehints_format == "short":
        kwargs.setdefault('unqualified_typehints', True)

    try:
        self.env.app.emit('autodoc-before-process-signature', self.object, False)
        sig = inspect.signature(self.object, type_aliases=self.config.autodoc_type_aliases)
        args = stringify_signature(sig, **kwargs)
    except TypeError as exc:
        logger.warning(__("Failed to get a function signature for %s: %s"),
                       self.fullname, exc)
        return None
    except ValueError:
        args = ''

    if self.config.strip_signature_backslash:
        # escape backslashes for reST
        args = args.replace('\\', '\\\\')
    return args

def format_args(self, **kwargs: Any) -> str:
    if self.config.autodoc_typehints in ('none', 'description'):
        kwargs.setdefault('show_annotation', False)
    if self.config.autodoc_typehints_format == "short":
        kwargs.setdefault('unqualified_typehints', True)

    try:
        self._signature_class, self._signature_method_name, sig = self._get_signature()
    except TypeError as exc:
        # __signature__ attribute contained junk
        logger.warning(__("Failed to get a constructor signature for %s: %s"),
                       self.fullname, exc)
        return None

    if sig is None:
        return None

    return stringify_signature(sig, show_return_annotation=False, **kwargs)

def get_user_defined_function_or_method(obj: Any, attr: str) -> Any:
    """ Get the `attr` function or method from `obj`, if it is user-defined. """
    if inspect.is_builtin_class_method(obj, attr):
        return None
    attr = self.get_attr(obj, attr, None)
    if not (inspect.ismethod(attr) or inspect.isfunction(attr)):
        return None
    return attr

def format_signature(self, **kwargs: Any) -> str:
    if self.args is None and self.config.autodoc_docstring_signature:  # type: ignore
        # only act if a signature is not explicitly given already, and if
        # the feature is enabled
        result = self._find_signature()
        if result is not None:
            self.args, self.retann = result
    sig = super().format_signature(**kwargs)  # type: ignore
    if self._signatures:
        return "\n".join([sig] + self._signatures)
    else:
        return sig

def _find_signature(self) -> Tuple[str, str]:
    # candidates of the object name
    valid_names = [self.objpath[-1]]  # type: ignore
    if isinstance(self, ClassDocumenter):
        valid_names.append('__init__')
        if hasattr(self.object, '__mro__'):
            valid_names.extend(cls.__name__ for cls in self.object.__mro__)

    docstrings = self.get_doc()
    if docstrings is None:
        return None, None
    self._new_docstrings = docstrings[:]
    self._signatures = []
    result = None
    for i, doclines in enumerate(docstrings):
        for j, line in enumerate(doclines):
            if not line:
                # no lines in docstring, no match
                break

            if line.endswith('\\'):
                line = line.rstrip('\\').rstrip()

            # match first line of docstring against signature RE
            match = py_ext_sig_re.match(line)
            if not match:
                break
            exmod, path, base, args, retann = match.groups()

            # the base name must match ours
            if base not in valid_names:
                break

            # re-prepare docstring to ignore more leading indentation
            tab_width = self.directive.state.document.settings.tab_width  # type: ignore
            self._new_docstrings[i] = prepare_docstring('\n'.join(doclines[j + 1:]),
                                                        tab_width)

            if result is None:
                # first signature
                result = args, retann
            else:
                # subsequent signatures
                self._signatures.append("(%s) -> %s" % (args, retann))

        if result:
            # finish the loop when signature found
            break

    return result

def prepend_prolog(content: StringList, prolog: str) -> None:
    """Prepend a string to content body as prolog."""
    if prolog:
        pos = 0
        for line in content:
            if docinfo_re.match(line):
                pos += 1
            else:
                break

        if pos > 0:
            # insert a blank line after docinfo
            content.insert(pos, '', '<generated>', 0)
            pos += 1

        # insert prolog (after docinfo if exists)
        for lineno, line in enumerate(prolog.splitlines()):
            content.insert(pos + lineno, line, '<rst_prolog>', lineno)

        content.insert(pos + lineno + 1, '', '<generated>', 0)

def resolve_xref(self, env: BuildEnvironment, fromdocname: str, builder: Builder,
                 typ: str, target: str, node: pending_xref, contnode: Element,
                 ) -> Element | None:
    objtypes = self.objtypes_for_role(typ)
    for objtype in objtypes:
        result = self.objects.get((objtype, target))
        if result:
            todocname, node_id = result
            return make_refnode(builder, fromdocname, todocname, node_id,
                                contnode, target + ' ' + objtype)
    return None

def setup(app: Sphinx) -> dict[str, Any]:
    app.add_source_parser(RSTParser)

    return {
        'version': 'builtin',
        'parallel_read_safe': True,
        'parallel_write_safe': True,
    }

def append_epilog(content: StringList, epilog: str) -> None:
    """Append a string to content body as epilog."""
    if epilog:
        if len(content) > 0:
            source, lineno = content.info(-1)
        else:
            source = '<generated>'
            lineno = 0
        content.append('', source, lineno + 1)
        for lineno, line in enumerate(epilog.splitlines()):
            content.append(line, '<rst_epilog>', lineno)

def note_object(self, objtype: str, name: str, node_id: str, location: Any = None) -> None:
    if (objtype, name) in self.objects:
        docname, node_id = self.objects[objtype, name]
        logger.warning(__('duplicate description of %s %s, other instance in %s') %
                       (objtype, name, docname), location=location)

    self.objects[objtype, name] = (self.env.docname, node_id)

def skip_member(obj: Any, name: str, objtype: str) -> bool:
    try:
        return app.emit_firstresult('autodoc-skip-member', objtype, name,
                                    obj, False, {})
    except Exception as exc:
        logger.warning(__('autosummary: failed to determine %r to be documented, '
                          'the following exception was raised:\n%s'),
                       name, exc, type='autosummary')
        return False

def get_import_prefixes_from_env(env: BuildEnvironment) -> List[str]:
    """
    Obtain current Python import prefixes (for `import_by_name`)
    from ``document.env``
    """
    prefixes = [None]  # type: List[str]

    currmodule = env.ref_context.get('py:module')
    if currmodule:
        prefixes.insert(0, currmodule)

    currclass = env.ref_context.get('py:class')
    if currclass:
        if currmodule:
            prefixes.insert(0, currmodule + "." + currclass)
        else:
            prefixes.insert(0, currclass)

    return prefixes

def import_by_name(name: str, prefixes: List[str] = [None]) -> Tuple[str, Any, Any, str]:
    """Import a Python object that has the given *name*, under one of the
    *prefixes*.  The first name that succeeds is used.
    """
    tried = []
    for prefix in prefixes:
        try:
            if prefix:
                prefixed_name = '.'.join([prefix, name])
            else:
                prefixed_name = name
            obj, parent, modname = _import_by_name(prefixed_name)
            return prefixed_name, obj, parent, modname
        except ImportError:
            tried.append(prefixed_name)
    raise ImportError('no module named %s' % ' or '.join(tried))

def safe_getmembers(object: Any, predicate: Callable[[str], bool] = None,
                    attr_getter: Callable = safe_getattr) -> List[Tuple[str, Any]]:
    """A version of inspect.getmembers() that uses safe_getattr()."""
    warnings.warn('safe_getmembers() is deprecated', RemovedInSphinx40Warning, stacklevel=2)

    results = []  # type: List[Tuple[str, Any]]
    for key in dir(object):
        try:
            value = attr_getter(object, key, None)
        except AttributeError:
            continue
        if not predicate or predicate(value):
            results.append((key, value))
    results.sort()
    return results

def get_module_attrs(members: Any) -> Tuple[List[str], List[str]]:
    """Find module attributes with docstrings."""
    attrs, public = [], []
    try:
        analyzer = ModuleAnalyzer.for_module(name)
        attr_docs = analyzer.find_attr_docs()
        for namespace, attr_name in attr_docs:
            if namespace == '' and attr_name in members:
                attrs.append(attr_name)
                if not attr_name.startswith('_'):
                    public.append(attr_name)
    except PycodeError:
        pass    # give up if ModuleAnalyzer fails to parse code
    return public, attrs

def generate_autosummary_content(name: str, obj: Any, parent: Any,
                                 template: AutosummaryRenderer, template_name: str,
                                 imported_members: bool, app: Any,
                                 recursive: bool, context: Dict) -> str:
    doc = get_documenter(app, obj, parent)

    def skip_member(obj: Any, name: str, objtype: str) -> bool:
        try:
            return app.emit_firstresult('autodoc-skip-member', objtype, name,
                                        obj, False, {})
        except Exception as exc:
            logger.warning(__('autosummary: failed to determine %r to be documented, '
                              'the following exception was raised:\n%s'),
                           name, exc, type='autosummary')
            return False

    def get_members(obj: Any, types: Set[str], include_public: List[str] = [],
                    imported: bool = True) -> Tuple[List[str], List[str]]:
        items = []  # type: List[str]
        public = []  # type: List[str]
        for name in dir(obj):
            try:
                value = safe_getattr(obj, name)
            except AttributeError:
                continue
            documenter = get_documenter(app, value, obj)
            if documenter.objtype in types:
                # skip imported members if expected
                if imported or getattr(value, '__module__', None) == obj.__name__:
                    skipped = skip_member(value, name, documenter.objtype)
                    if skipped is True:
                        pass
                    elif skipped is False:
                        # show the member forcedly
                        items.append(name)
                        public.append(name)
                    else:
                        items.append(name)
                        if name in include_public or not name.startswith('_'):
                            # considers member as public
                            public.append(name)
        return public, items

    def get_module_attrs(members: Any) -> Tuple[List[str], List[str]]:
        """Find module attributes with docstrings."""
        attrs, public = [], []
        try:
            analyzer = ModuleAnalyzer.for_module(name)
            attr_docs = analyzer.find_attr_docs()
            for namespace, attr_name in attr_docs:
                if namespace == '' and attr_name in members:
                    attrs.append(attr_name)
                    if not attr_name.startswith('_'):
                        public.append(attr_name)
        except PycodeError:
            pass    # give up if ModuleAnalyzer fails to parse code
        return public, attrs

    def get_modules(obj: Any) -> Tuple[List[str], List[str]]:
        items = []  # type: List[str]
        for _, modname, ispkg in pkgutil.iter_modules(obj.__path__):
            fullname = name + '.' + modname
            items.append(fullname)
        public = [x for x in items if not x.split('.')[-1].startswith('_')]
        return public, items

    ns = {}  # type: Dict[str, Any]
    ns.update(context)

    if doc.objtype == 'module':
        ns['members'] = dir(obj)
        ns['functions'], ns['all_functions'] = \
            get_members(obj, {'function'}, imported=imported_members)
        ns['classes'], ns['all_classes'] = \
            get_members(obj, {'class'}, imported=imported_members)
        ns['exceptions'], ns['all_exceptions'] = \
            get_members(obj, {'exception'}, imported=imported_members)
        ns['attributes'], ns['all_attributes'] = \
            get_module_attrs(ns['members'])
        ispackage = hasattr(obj, '__path__')
        if ispackage and recursive:
            ns['modules'], ns['all_modules'] = get_modules(obj)
    elif doc.objtype == 'class':
        ns['members'] = dir(obj)
        ns['inherited_members'] = \
            set(dir(obj)) - set(obj.__dict__.keys())
        ns['methods'], ns['all_methods'] = \
            get_members(obj, {'method'}, ['__init__'])
        ns['attributes'], ns['all_attributes'] = \
            get_members(obj, {'attribute', 'property'})

    modname, qualname = split_full_qualified_name(name)
    if doc.objtype in ('method', 'attribute', 'property'):
        ns['class'] = qualname.rsplit(".", 1)[0]

    if doc.objtype in ('class',):
        shortname = qualname
    else:
        shortname = qualname.rsplit(".", 1)[-1]

    ns['fullname'] = name
    ns['module'] = modname
    ns['objname'] = qualname
    ns['name'] = shortname

    ns['objtype'] = doc.objtype
    ns['underline'] = len(name) * '='

    if template_name:
        return template.render(template_name, ns)
    else:
        return template.render(doc.objtype, ns)

def prepare_docstring(s: str, ignore: int = None, tabsize: int = 8) -> List[str]:
    """Convert a docstring into lines of parseable reST.  Remove common leading
    indentation, where the indentation of a given number of lines (usually just
    one) is ignored.

    Return the docstring as a list of lines usable for inserting into a docutils
    ViewList (used as argument of nested_parse().)  An empty line is added to
    act as a separator between this docstring and following content.
    """
    if ignore is None:
        ignore = 1
    else:
        warnings.warn("The 'ignore' argument to parepare_docstring() is deprecated.",
                      RemovedInSphinx50Warning, stacklevel=2)

    lines = s.expandtabs(tabsize).splitlines()
    # Find minimum indentation of any non-blank lines after ignored lines.
    margin = sys.maxsize
    for line in lines[ignore:]:
        content = len(line.lstrip())
        if content:
            indent = len(line) - content
            margin = min(margin, indent)
    # Remove indentation from ignored lines.
    for i in range(ignore):
        if i < len(lines):
            lines[i] = lines[i].lstrip()
    if margin < sys.maxsize:
        for i in range(ignore, len(lines)):
            lines[i] = lines[i][margin:]
    # Remove any leading blank lines.
    while lines and not lines[0]:
        lines.pop(0)
    # make sure there is an empty line at the end
    if lines and lines[-1]:
        lines.append('')
    return lines

def _parse_attributes_section(self, section: str) -> List[str]:
    lines = []
    for _name, _type, _desc in self._consume_fields():
        if self._config.napoleon_use_ivar:
            _name = self._qualify_name(_name, self._obj)
            field = ':ivar %s: ' % _name
            lines.extend(self._format_block(field, _desc))
            if _type:
                lines.append(':vartype %s: %s' % (_name, _type))
        else:
            lines.append('.. attribute:: ' + _name)
            if self._opt and 'noindex' in self._opt:
                lines.append('   :noindex:')
            if _type:
                lines.extend(self._indent([':type: %s' % _type], 3))
            lines.append('')

            fields = self._format_field('', '', _desc)
            lines.extend(self._indent(fields, 3))
            lines.append('')
    if self._config.napoleon_use_ivar:
        lines.append('')
    return lines

def _format_block(self, prefix: str, lines: List[str], padding: str = None) -> List[str]:
    if lines:
        if padding is None:
            padding = ' ' * len(prefix)
        result_lines = []
        for i, line in enumerate(lines):
            if i == 0:
                result_lines.append((prefix + line).rstrip())
            elif line:
                result_lines.append(padding + line)
            else:
                result_lines.append('')
        return result_lines
    else:
        return [prefix]

def _consume_fields(self, parse_type: bool = True, prefer_type: bool = False
                    ) -> List[Tuple[str, str, List[str]]]:
    self._consume_empty()
    fields = []
    while not self._is_section_break():
        _name, _type, _desc = self._consume_field(parse_type, prefer_type)
        if _name or _type or _desc:
            fields.append((_name, _type, _desc,))
    return fields

def _escape_args_and_kwargs(self, name: str) -> str:
    if name.endswith('_'):
        name = name[:-1] + r'\_'

    if name[:2] == '**':
        return r'\*\*' + name[2:]
    elif name[:1] == '*':
        return r'\*' + name[1:]
    else:
        return name

def _partition_field_on_colon(self, line: str) -> Tuple[str, str, str]:
    before_colon = []
    after_colon = []
    colon = ''
    found_colon = False
    for i, source in enumerate(_xref_or_code_regex.split(line)):
        if found_colon:
            after_colon.append(source)
        else:
            m = _single_colon_regex.search(source)
            if (i % 2) == 0 and m:
                found_colon = True
                colon = source[m.start(): m.end()]
                before_colon.append(source[:m.start()])
                after_colon.append(source[m.end():])
            else:
                before_colon.append(source)

    return ("".join(before_colon).strip(),
            colon,
            "".join(after_colon).strip())

def _strip_empty(self, lines: List[str]) -> List[str]:
    if lines:
        start = -1
        for i, line in enumerate(lines):
            if line:
                start = i
                break
        if start == -1:
            lines = []
        end = -1
        for i in reversed(range(len(lines))):
            line = lines[i]
            if line:
                end = i
                break
        if start > 0 or end + 1 < len(lines):
            lines = lines[start:end + 1]
    return lines

def create_index(self, builder: Builder, group_entries: bool = True,
                 _fixre: Pattern = re.compile(r'(.*) ([(][^()]*[)])')
                 ) -> List[Tuple[str, List[Tuple[str, Any]]]]:
    """Create the real index from the collected index entries."""
    new = {}  # type: Dict[str, List]

    def add_entry(word: str, subword: str, main: str, link: bool = True,
                  dic: Dict = new, key: str = None) -> None:
        # Force the word to be unicode if it's a ASCII bytestring.
        # This will solve problems with unicode normalization later.
        # For instance the RFC role will add bytestrings at the moment
        word = str(word)
        entry = dic.get(word)
        if not entry:
            dic[word] = entry = [[], {}, key]
        if subword:
            add_entry(subword, '', main, link=link, dic=entry[1], key=key)
        elif link:
            try:
                uri = builder.get_relative_uri('genindex', fn) + '#' + tid
            except NoUri:
                pass
            else:
                entry[0].append((main, uri))

    domain = cast(IndexDomain, self.env.get_domain('index'))
    for fn, entries in domain.entries.items():
        # new entry types must be listed in directives/other.py!
        for type, value, tid, main, index_key in entries:
            try:
                if type == 'single':
                    try:
                        entry, subentry = split_into(2, 'single', value)
                    except ValueError:
                        entry, = split_into(1, 'single', value)
                        subentry = ''
                    add_entry(entry, subentry, main, key=index_key)
                elif type == 'pair':
                    first, second = split_into(2, 'pair', value)
                    add_entry(first, second, main, key=index_key)
                    add_entry(second, first, main, key=index_key)
                elif type == 'triple':
                    first, second, third = split_into(3, 'triple', value)
                    add_entry(first, second + ' ' + third, main, key=index_key)
                    add_entry(second, third + ', ' + first, main, key=index_key)
                    add_entry(third, first + ' ' + second, main, key=index_key)
                elif type == 'see':
                    first, second = split_into(2, 'see', value)
                    add_entry(first, _('see %s') % second, None,
                              link=False, key=index_key)
                elif type == 'seealso':
                    first, second = split_into(2, 'see', value)
                    add_entry(first, _('see also %s') % second, None,
                              link=False, key=index_key)
                else:
                    logger.warning(__('unknown index entry type %r'), type, location=fn)
            except ValueError as err:
                logger.warning(str(err), location=fn)

    # sort the index entries for same keyword.
    def keyfunc0(entry: Tuple[str, str]) -> Tuple[bool, str]:
        main, uri = entry
        return (not main, uri)  # show main entries at first

    for indexentry in new.values():
        indexentry[0].sort(key=keyfunc0)
        for subentry in indexentry[1].values():
            subentry[0].sort(key=keyfunc0)  # type: ignore

    # sort the index entries; put all symbols at the front, even those
    # following the letters in ASCII, this is where the chr(127) comes from
    def keyfunc(entry: Tuple[str, List]) -> Tuple[str, str]:
        key, (void, void, category_key) = entry
        if category_key:
            # using specified category key to sort
            key = category_key
        lckey = unicodedata.normalize('NFD', key.lower())
        if lckey.startswith('\N{RIGHT-TO-LEFT MARK}'):
            lckey = lckey[1:]
        if lckey[0:1].isalpha() or lckey.startswith('_'):
            lckey = chr(127) + lckey
        # ensure a determinstic order *within* letters by also sorting on
        # the entry itself
        return (lckey, entry[0])
    newlist = sorted(new.items(), key=keyfunc)

    if group_entries:
        # fixup entries: transform
        #   func() (in module foo)
        #   func() (in module bar)
        # into
        #   func()
        #     (in module foo)
        #     (in module bar)
        oldkey = ''
        oldsubitems = None  # type: Dict[str, List]
        i = 0
        while i < len(newlist):
            key, (targets, subitems, _key) = newlist[i]
            # cannot move if it has subitems; structure gets too complex
            if not subitems:
                m = _fixre.match(key)
                if m:
                    if oldkey == m.group(1):
                        # prefixes match: add entry as subitem of the
                        # previous entry
                        oldsubitems.setdefault(m.group(2), [[], {}, _key])[0].\
                            extend(targets)
                        del newlist[i]
                        continue
                    oldkey = m.group(1)
                else:
                    oldkey = key
            oldsubitems = subitems
            i += 1

    # sort the sub-index entries
    def keyfunc2(entry: Tuple[str, List]) -> str:
        key = unicodedata.normalize('NFD', entry[0].lower())
        if key.startswith('\N{RIGHT-TO-LEFT MARK}'):
            key = key[1:]
        if key[0:1].isalpha() or key.startswith('_'):
            key = chr(127) + key
        return key

    # group the entries by letter
    def keyfunc3(item: Tuple[str, List]) -> str:
        # hack: mutating the subitems dicts to a list in the keyfunc
        k, v = item
        v[1] = sorted(((si, se) for (si, (se, void, void)) in v[1].items()),
                      key=keyfunc2)
        if v[2] is None:
            # now calculate the key
            if k.startswith('\N{RIGHT-TO-LEFT MARK}'):
                k = k[1:]
            letter = unicodedata.normalize('NFD', k[0])[0].upper()
            if letter.isalpha() or letter == '_':
                return letter
            else:
                # get all other symbols under one heading
                return _('Symbols')
        else:
            return v[2]
    return [(key_, list(group))
            for (key_, group) in groupby(newlist, keyfunc3)]

def setup(app: Sphinx) -> Dict[str, Any]:
    app.add_env_collector(IndexEntriesCollector)

    return {
        'version': 'builtin',
        'parallel_read_safe': True,
        'parallel_write_safe': True,
    }

def process_doc(self, env: BuildEnvironment, docname: str, document: Node) -> None:
    """Process a document after it is read by the environment."""
    entries = self.entries.setdefault(env.docname, [])
    for node in document.traverse(addnodes.index):
        try:
            for entry in node['entries']:
                split_index_msg(entry[0], entry[1])
        except ValueError as exc:
            logger.warning(str(exc), location=node)
            node.parent.remove(node)
        else:
            for entry in node['entries']:
                entries.append(entry)

def default_man_pages(config: Config) -> List[Tuple[str, str, str, List[str], int]]:
    """ Better default man_pages settings. """
    filename = make_filename_from_project(config.project)
    return [(config.master_doc, filename, '%s %s' % (config.project, config.release),
             [config.author], 1)]

