    }

def get_target_uri(self, docname: str, typ: str = None) -> str:
    if typ == 'token':
        return ''
    raise NoUri(docname, typ)

def init(self) -> None:
    if not self.config.man_pages:
        logger.warning(__('no "man_pages" config value found; no manual pages '
                          'will be written'))

def build(self, force_all: bool = False, filenames: List[str] = None) -> None:
    self.phase = BuildPhase.READING
    try:
        if force_all:
            self.builder.compile_all_catalogs()
            self.builder.build_all()
        elif filenames:
            self.builder.compile_specific_catalogs(filenames)
            self.builder.build_specific(filenames)
        else:
            self.builder.compile_update_catalogs()
            self.builder.build_update()

        if self._warncount and self.keep_going:
            self.statuscode = 1

        status = (__('succeeded') if self.statuscode == 0
                  else __('finished with problems'))
        if self._warncount:
            if self.warningiserror:
                if self._warncount == 1:
                    msg = __('build %s, %s warning (with warnings treated as errors).')
                else:
                    msg = __('build %s, %s warnings (with warnings treated as errors).')
            else:
                if self._warncount == 1:
                    msg = __('build %s, %s warning.')
                else:
                    msg = __('build %s, %s warnings.')

            logger.info(bold(msg % (status, self._warncount)))
        else:
            logger.info(bold(__('build %s.') % status))

        if self.statuscode == 0 and self.builder.epilog:
            logger.info('')
            logger.info(self.builder.epilog % {
                'outdir': relpath(self.outdir),
                'project': self.config.project
            })
    except Exception as err:
        # delete the saved env to force a fresh build next time
        envfile = path.join(self.doctreedir, ENV_PICKLE_FILENAME)
        if path.isfile(envfile):
            os.unlink(envfile)
        self.events.emit('build-finished', err)
        raise
    else:
        self.events.emit('build-finished', None)
    self.builder.cleanup()

def merge_typehints(app: Sphinx, domain: str, objtype: str, contentnode: Element) -> None:
    if domain != 'py':
        return
    if app.config.autodoc_typehints != 'description':
        return
    if objtype == 'class' and app.config.autoclass_content not in ('init', 'both'):
        return

    try:
        signature = cast(addnodes.desc_signature, contentnode.parent[0])
        if signature['module']:
            fullname = '.'.join([signature['module'], signature['fullname']])
        else:
            fullname = signature['fullname']
    except KeyError:
        # signature node does not have valid context info for the target object
        return

    annotations = app.env.temp_data.get('annotations', {})
    if annotations.get(fullname, {}):
        field_lists = [n for n in contentnode if isinstance(n, nodes.field_list)]
        if field_lists == []:
            field_list = insert_field_list(contentnode)
            field_lists.append(field_list)

        for field_list in field_lists:
            modify_field_list(field_list, annotations[fullname])

def format_signature(self, **kwargs: Any) -> str:
    sigs = []
    if self.analyzer and '.'.join(self.objpath) in self.analyzer.overloads:
        # Use signatures for overloaded functions instead of the implementation function.
        overloaded = True
    else:
        overloaded = False
        sig = super().format_signature(**kwargs)
        sigs.append(sig)

    if inspect.is_singledispatch_function(self.object):
        # append signature of singledispatch'ed functions
        for typ, func in self.object.registry.items():
            if typ is object:
                pass  # default implementation. skipped.
            else:
                self.annotate_to_first_argument(func, typ)

                documenter = FunctionDocumenter(self.directive, '')
                documenter.object = func
                documenter.objpath = [None]
                sigs.append(documenter.format_signature())
    if overloaded:
        __globals__ = safe_getattr(self.object, '__globals__', {})
        for overload in self.analyzer.overloads.get('.'.join(self.objpath)):
            overload = evaluate_signature(overload, __globals__,
                                          self.env.config.autodoc_type_aliases)

            sig = stringify_signature(overload, **kwargs)
            sigs.append(sig)

    return "\n".join(sigs)

def get_overloaded_signatures(self) -> List[Signature]:
    if self._signature_class and self._signature_method_name:
        for cls in self._signature_class.__mro__:
            try:
                analyzer = ModuleAnalyzer.for_module(cls.__module__)
                analyzer.parse()
                qualname = '.'.join([cls.__qualname__, self._signature_method_name])
                if qualname in analyzer.overloads:
                    return analyzer.overloads.get(qualname)
            except PycodeError:
                pass

    return []

def _getannotations(obj: Any) -> Mapping[str, Any]:
    """Get __annotations__ from given *obj* safely."""
    __annotations__ = safe_getattr(obj, '__annotations__', None)
    if isinstance(__annotations__, Mapping):
        return __annotations__
    else:
        return {}

def record_typehints(app: Sphinx, objtype: str, name: str, obj: Any,
                     options: Dict, args: str, retann: str) -> None:
    """Record type hints to env object."""
    try:
        if callable(obj):
            annotations = app.env.temp_data.setdefault('annotations', {})
            annotation = annotations.setdefault(name, OrderedDict())
            sig = inspect.signature(obj)
            for param in sig.parameters.values():
                if param.annotation is not param.empty:
                    annotation[param.name] = typing.stringify(param.annotation)
            if sig.return_annotation is not sig.empty:
                annotation['return'] = typing.stringify(sig.return_annotation)
    except (TypeError, ValueError):
        pass

def insert_field_list(node: Element) -> nodes.field_list:
    field_list = nodes.field_list()
    desc = [n for n in node if isinstance(n, addnodes.desc)]
    if desc:
        # insert just before sub object descriptions (ex. methods, nested classes, etc.)
        index = node.index(desc[0])
        node.insert(index - 1, [field_list])
    else:
        node += field_list

    return field_list

def modify_field_list(node: nodes.field_list, annotations: Dict[str, str]) -> None:
    arguments = {}  # type: Dict[str, Dict[str, bool]]
    fields = cast(Iterable[nodes.field], node)
    for field in fields:
        field_name = field[0].astext()
        parts = re.split(' +', field_name)
        if parts[0] == 'param':
            if len(parts) == 2:
                # :param xxx:
                arg = arguments.setdefault(parts[1], {})
                arg['param'] = True
            elif len(parts) > 2:
                # :param xxx yyy:
                name = ' '.join(parts[2:])
                arg = arguments.setdefault(name, {})
                arg['param'] = True
                arg['type'] = True
        elif parts[0] == 'type':
            name = ' '.join(parts[1:])
            arg = arguments.setdefault(name, {})
            arg['type'] = True
        elif parts[0] == 'rtype':
            arguments['return'] = {'type': True}

    for name, annotation in annotations.items():
        if name == 'return':
            continue

        arg = arguments.get(name, {})
        if not arg.get('type'):
            field = nodes.field()
            field += nodes.field_name('', 'type ' + name)
            field += nodes.field_body('', nodes.paragraph('', annotation))
            node += field
        if not arg.get('param'):
            field = nodes.field()
            field += nodes.field_name('', 'param ' + name)
            field += nodes.field_body('', nodes.paragraph('', ''))
            node += field

    if 'return' in annotations and 'return' not in arguments:
        field = nodes.field()
        field += nodes.field_name('', 'rtype')
        field += nodes.field_body('', nodes.paragraph('', annotation))
        node += field

def annotate_to_first_argument(self, func: Callable, typ: Type) -> None:
    """Annotate type hint to the first argument of function if needed."""
    try:
        sig = inspect.signature(func, type_aliases=self.env.config.autodoc_type_aliases)
    except TypeError as exc:
        logger.warning(__("Failed to get a function signature for %s: %s"),
                       self.fullname, exc)
        return
    except ValueError:
        return

    if len(sig.parameters) == 0:
        return

    params = list(sig.parameters.values())
    if params[0].annotation is Parameter.empty:
        params[0] = params[0].replace(annotation=typ)
        try:
            func.__signature__ = sig.replace(parameters=params)  # type: ignore
        except TypeError:
            # failed to update signature (ex. built-in or extension types)
            return

def assign_figure_numbers(self, env: BuildEnvironment) -> List[str]:
    """Assign a figure number to each figure under a numbered toctree."""

    rewrite_needed = []

    assigned = set()  # type: Set[str]
    old_fignumbers = env.toc_fignumbers
    env.toc_fignumbers = {}
    fignum_counter = {}  # type: Dict[str, Dict[Tuple[int, ...], int]]

    def get_figtype(node: Node) -> str:
        for domain in env.domains.values():
            figtype = domain.get_enumerable_node_type(node)
            if domain.name == 'std' and not domain.get_numfig_title(node):  # type: ignore
                # Skip if uncaptioned node
                continue

            if figtype:
                return figtype

        return None

    def get_section_number(docname: str, section: nodes.section) -> Tuple[int, ...]:
        anchorname = '#' + section['ids'][0]
        secnumbers = env.toc_secnumbers.get(docname, {})
        if anchorname in secnumbers:
            secnum = secnumbers.get(anchorname)
        else:
            secnum = secnumbers.get('')

        return secnum or tuple()

    def get_next_fignumber(figtype: str, secnum: Tuple[int, ...]) -> Tuple[int, ...]:
        counter = fignum_counter.setdefault(figtype, {})

        secnum = secnum[:env.config.numfig_secnum_depth]
        counter[secnum] = counter.get(secnum, 0) + 1
        return secnum + (counter[secnum],)

    def register_fignumber(docname: str, secnum: Tuple[int, ...],
                           figtype: str, fignode: Element) -> None:
        env.toc_fignumbers.setdefault(docname, {})
        fignumbers = env.toc_fignumbers[docname].setdefault(figtype, {})
        figure_id = fignode['ids'][0]

        fignumbers[figure_id] = get_next_fignumber(figtype, secnum)

    def _walk_doctree(docname: str, doctree: Element, secnum: Tuple[int, ...]) -> None:
        for subnode in doctree.children:
            if isinstance(subnode, nodes.section):
                next_secnum = get_section_number(docname, subnode)
                if next_secnum:
                    _walk_doctree(docname, subnode, next_secnum)
                else:
                    _walk_doctree(docname, subnode, secnum)
            elif isinstance(subnode, addnodes.toctree):
                for title, subdocname in subnode['entries']:
                    if url_re.match(subdocname) or subdocname == 'self':
                        # don't mess with those
                        continue

                    _walk_doc(subdocname, secnum)
            elif isinstance(subnode, nodes.Element):
                figtype = get_figtype(subnode)
                if figtype and subnode['ids']:
                    register_fignumber(docname, secnum, figtype, subnode)

                _walk_doctree(docname, subnode, secnum)

    def _walk_doc(docname: str, secnum: Tuple[int, ...]) -> None:
        if docname not in assigned:
            assigned.add(docname)
            doctree = env.get_doctree(docname)
            _walk_doctree(docname, doctree, secnum)

    if env.config.numfig:
        _walk_doc(env.config.master_doc, tuple())
        for docname, fignums in env.toc_fignumbers.items():
            if fignums != old_fignumbers.get(docname):
                rewrite_needed.append(docname)

    return rewrite_needed

def get_next_fignumber(figtype: str, secnum: Tuple[int, ...]) -> Tuple[int, ...]:
    counter = fignum_counter.setdefault(figtype, {})

    secnum = secnum[:env.config.numfig_secnum_depth]
    counter[secnum] = counter.get(secnum, 0) + 1
    return secnum + (counter[secnum],)

def assemble_toc_fignumbers(self) -> Dict[str, Dict[str, Dict[str, Tuple[int, ...]]]]:
    # Assemble toc_fignumbers to resolve figure numbers on SingleHTML.
    # Merge all fignumbers to single fignumber.
    #
    # Note: current Sphinx has refid confliction in singlehtml mode.
    #       To avoid the problem, it replaces key of secnumbers to
    #       tuple of docname and refid.
    #
    #       There are related codes in inline_all_toctres() and
    #       HTMLTranslter#add_fignumber().
    new_fignumbers = {}  # type: Dict[str, Dict[str, Tuple[int, ...]]]
    # {'foo': {'figure': {'id2': (2,), 'id1': (1,)}}, 'bar': {'figure': {'id1': (3,)}}}
    for docname, fignumlist in self.env.toc_fignumbers.items():
        for figtype, fignums in fignumlist.items():
            alias = "%s/%s" % (docname, figtype)
            new_fignumbers.setdefault(alias, {})
            for id, fignum in fignums.items():
                new_fignumbers[alias][id] = fignum

    return {self.config.master_doc: new_fignumbers}

def _resolve_option_xref(self, env: "BuildEnvironment", fromdocname: str,
                         builder: "Builder", typ: str, target: str,
                         node: pending_xref, contnode: Element) -> Element:
    progname = node.get('std:program')
    target = target.strip()
    docname, labelid = self.progoptions.get((progname, target), ('', ''))
    if not docname:
        commands = []
        while ws_re.search(target):
            subcommand, target = ws_re.split(target, 1)
            commands.append(subcommand)
            progname = "-".join(commands)

            docname, labelid = self.progoptions.get((progname, target), ('', ''))
            if docname:
                break
        else:
            return None

    return make_refnode(builder, fromdocname, docname,
                        labelid, contnode)

def warn_missing_reference(app: "Sphinx", domain: Domain, node: pending_xref) -> bool:
    if (domain and domain.name != 'std') or node['reftype'] != 'ref':
        return None
    else:
        target = node['reftarget']
        if target not in domain.anonlabels:  # type: ignore
            msg = __('undefined label: %s')
        else:
            msg = __('Failed to create a cross reference. A title or caption not found: %s')

        logger.warning(msg % target, location=node, type='ref', subtype=node['reftype'])
        return True

def get_module_members(self) -> Dict[str, ObjectMember]:
    """Get members of target module."""
    if self.analyzer:
        attr_docs = self.analyzer.attr_docs
    else:
        attr_docs = {}

    members = {}  # type: Dict[str, ObjectMember]
    for name in dir(self.object):
        try:
            value = safe_getattr(self.object, name, None)
            docstring = attr_docs.get(('', name), [])
            members[name] = ObjectMember(name, value, docstring="\n".join(docstring))
        except AttributeError:
            continue

    # annotation only member (ex. attr: int)
    try:
        for name in inspect.getannotations(self.object):
            if name not in members:
                docstring = attr_docs.get(('', name), [])
                members[name] = ObjectMember(name, INSTANCEATTR,
                                             docstring="\n".join(docstring))
    except AttributeError:
        pass

    return members

def get_object_members(self, want_all: bool) -> Tuple[bool, ObjectMembers]:
    members = self.get_module_members()
    if want_all:
        if not self.__all__:
            # for implicit module members, check __module__ to avoid
            # documenting imported objects
            return True, list(members.values())
        else:
            for member in members.values():
                if member.__name__ not in self.__all__:
                    member.skipped = True

            return False, list(members.values())
    else:
        memberlist = self.options.members or []
        ret = []
        for name in memberlist:
            if name in members:
                ret.append(members[name])
            else:
                logger.warning(__('missing attribute mentioned in :members: option: '
                                  'module %s, attribute %s') %
                               (safe_getattr(self.object, '__name__', '???'), name),
                               type='autodoc')
        return False, ret

def resolve_name(self, modname: str, parents: Any, path: str, base: Any
                 ) -> Tuple[str, List[str]]:
    if modname is not None:
        logger.warning(__('"::" in automodule name doesn\'t make sense'),
                       type='autodoc')
    return (path or '') + base, []

def _parse_numpydoc_see_also_section(self, content: List[str]) -> List[str]:
    """
    Derived from the NumpyDoc implementation of _parse_see_also.

    See Also
    --------
    func_name : Descriptive text
        continued text
    another_func_name : Descriptive text
    func_name1, func_name2, :meth:`func_name`, func_name3

    """
    items = []

    def parse_item_name(text: str) -> Tuple[str, str]:
        """Match ':role:`name`' or 'name'"""
        m = self._name_rgx.match(text)
        if m:
            g = m.groups()
            if g[1] is None:
                return g[3], None
            else:
                return g[2], g[1]
        raise ValueError("%s is not a item name" % text)

    def push_item(name: str, rest: List[str]) -> None:
        if not name:
            return
        name, role = parse_item_name(name)
        items.append((name, list(rest), role))
        del rest[:]

    def translate(func, description, role):
        translations = self._config.napoleon_type_aliases
        if role is not None or not translations:
            return func, description, role

        translated = translations.get(func, func)
        match = self._name_rgx.match(translated)
        if not match:
            return translated, description, role

        groups = match.groupdict()
        role = groups["role"]
        new_func = groups["name"] or groups["name2"]

        return new_func, description, role

    current_func = None
    rest = []  # type: List[str]

    for line in content:
        if not line.strip():
            continue

        m = self._name_rgx.match(line)
        if m and line[m.end():].strip().startswith(':'):
            push_item(current_func, rest)
            current_func, line = line[:m.end()], line[m.end():]
            rest = [line.split(':', 1)[1].strip()]
            if not rest[0]:
                rest = []
        elif not line.startswith(' '):
            push_item(current_func, rest)
            current_func = None
            if ',' in line:
                for func in line.split(','):
                    if func.strip():
                        push_item(func, [])
            elif line.strip():
                current_func = line
        elif current_func is not None:
            rest.append(line.strip())
    push_item(current_func, rest)

    if not items:
        return []

    # apply type aliases
    items = [
        translate(func, description, role)
        for func, description, role in items
    ]

    lines = []  # type: List[str]
    last_had_desc = True
    for name, desc, role in items:
        if role:
            link = ':%s:`%s`' % (role, name)
        else:
            link = ':obj:`%s`' % name
        if desc or last_had_desc:
            lines += ['']
            lines += [link]
        else:
            lines[-1] += ", %s" % link
        if desc:
            lines += self._indent([' '.join(desc)])
            last_had_desc = True
        else:
            last_had_desc = False
    lines += ['']

    return self._format_admonition('seealso', lines)

def _parse_see_also_section(self, section: str) -> List[str]:
    lines = self._consume_to_next_section()
    try:
        return self._parse_numpydoc_see_also_section(lines)
    except ValueError:
        return self._format_admonition('seealso', lines)

def _consume_section_header(self) -> str:
    section = next(self._line_iter)
    if not _directive_regex.match(section):
        # Consume the header underline
        next(self._line_iter)
    return section

def has_tag(modname: str, fullname: str, docname: str, refname: str) -> bool:
    entry = env._viewcode_modules.get(modname, None)  # type: ignore
    if entry is False:
        return False

    code_tags = app.emit_firstresult('viewcode-find-source', modname)
    if code_tags is None:
        try:
            analyzer = ModuleAnalyzer.for_module(modname)
            analyzer.find_tags()
        except Exception:
            env._viewcode_modules[modname] = False  # type: ignore
            return False

        code = analyzer.code
        tags = analyzer.tags
    else:
        code, tags = code_tags

    if entry is None or entry[0] != code:
        entry = code, tags, {}, refname
        env._viewcode_modules[modname] = entry  # type: ignore
    _, tags, used, _ = entry
    if fullname in tags:
        used[fullname] = docname
        return True

    return False

def check_confval_types(app: "Sphinx", config: Config) -> None:
    """check all values for deviation from the default value's type, since
    that can result in TypeErrors all over the place NB.
    """
    for confval in config:
        default, rebuild, annotations = config.values[confval.name]

        if hasattr(default, '__call__'):
            default = default(config)  # evaluate default value
        if default is None and not annotations:
            continue  # neither inferrable nor expliclitly annotated types

        if annotations is Any:
            # any type of value is accepted
            pass
        elif isinstance(annotations, ENUM):
            if not annotations.match(confval.value):
                msg = __("The config value `{name}` has to be a one of {candidates}, "
                         "but `{current}` is given.")
                logger.warning(msg.format(name=confval.name,
                                          current=confval.value,
                                          candidates=annotations.candidates))
        else:
            if type(confval.value) is type(default):
                continue
            if type(confval.value) in annotations:
                continue

            common_bases = (set(type(confval.value).__bases__ + (type(confval.value),)) &
                            set(type(default).__bases__))
            common_bases.discard(object)
            if common_bases:
                continue  # at least we share a non-trivial base class

            if annotations:
                msg = __("The config value `{name}' has type `{current.__name__}'; "
                         "expected {permitted}.")
                wrapped_annotations = ["`{}'".format(c.__name__) for c in annotations]
                if len(wrapped_annotations) > 2:
                    permitted = "{}, or {}".format(
                        ", ".join(wrapped_annotations[:-1]),
                        wrapped_annotations[-1])
                else:
                    permitted = " or ".join(wrapped_annotations)
                logger.warning(msg.format(name=confval.name,
                                          current=type(confval.value),
                                          permitted=permitted))
            else:
                msg = __("The config value `{name}' has type `{current.__name__}', "
                         "defaults to `{default.__name__}'.")
                logger.warning(msg.format(name=confval.name,
                                          current=type(confval.value),
                                          default=type(default)))

def get_module_filename(app: Sphinx, modname: str) -> Optional[str]:
    """Get module filename for *modname*."""
    source_info = app.emit_firstresult('viewcode-find-source', modname)
    if source_info:
        return None
    else:
        try:
            filename, source = ModuleAnalyzer.get_module_source(modname)
            return filename
        except Exception:
            return None

def missing_reference(app: Sphinx, env: BuildEnvironment, node: Element, contnode: Node
                      ) -> Optional[Node]:
    # resolve our "viewcode" reference nodes -- they need special treatment
    if node['reftype'] == 'viewcode':
        return make_refnode(app.builder, node['refdoc'], node['reftarget'],
                            node['refid'], contnode)

    return None

def _get_full_modname(app: Sphinx, modname: str, attribute: str) -> Optional[str]:
    try:
        return get_full_modname(modname, attribute)
    except AttributeError:
        # sphinx.ext.viewcode can't follow class instance attribute
        # then AttributeError logging output only verbose mode.
        logger.verbose('Didn\'t find %s in %s', attribute, modname)
        return None
    except Exception as e:
        # sphinx.ext.viewcode follow python domain directives.
        # because of that, if there are no real modules exists that specified
        # by py:function or other directives, viewcode emits a lot of warnings.
        # It should be displayed only verbose mode.
        logger.verbose(traceback.format_exc().rstrip())
        logger.verbose('viewcode can\'t import %s, failed with error "%s"', modname, e)
        return None

def env_merge_info(app: Sphinx, env: BuildEnvironment, docnames: Iterable[str],
                   other: BuildEnvironment) -> None:
    if not hasattr(other, '_viewcode_modules'):
        return
    # create a _viewcode_modules dict on the main environment
    if not hasattr(env, '_viewcode_modules'):
        env._viewcode_modules = {}  # type: ignore
    # now merge in the information from the subprocess
    env._viewcode_modules.update(other._viewcode_modules)  # type: ignore

def document_members(self, all_members: bool = False) -> None:
    if self.doc_as_attr:
        return
    super().document_members(all_members)

def can_document_member(cls, member: Any, membername: str, isattr: bool, parent: Any
                        ) -> bool:
    if inspect.isattributedescriptor(member):
        return True
    elif (not isinstance(parent, ModuleDocumenter) and
          not inspect.isroutine(member) and
          not isinstance(member, type)):
        return True
    else:
        return False

def update_annotations(self, parent: Any) -> None:
    """Update __annotations__ to support type_comment and so on."""
    try:
        annotations = dict(inspect.getannotations(parent))
        parent.__annotations__ = annotations

        for cls in inspect.getmro(parent):
            try:
                module = safe_getattr(cls, '__module__')
                qualname = safe_getattr(cls, '__qualname__')

                analyzer = ModuleAnalyzer.for_module(module)
                analyzer.analyze()
                for (classname, attrname), annotation in analyzer.annotations.items():
                    if classname == qualname and attrname not in annotations:
                        annotations[attrname] = annotation
            except (AttributeError, PycodeError):
                pass
    except TypeError:
        # Failed to set __annotations__ (built-in, extensions, etc.)
        pass

def get_class_members(subject: Any, objpath: List[str], attrgetter: Callable
                      ) -> Dict[str, "ObjectMember"]:
    """Get members and attributes of target class."""
    from sphinx.ext.autodoc import INSTANCEATTR, ObjectMember

    # the members directly defined in the class
    obj_dict = attrgetter(subject, '__dict__', {})

    members = {}  # type: Dict[str, ObjectMember]

    # enum members
    if isenumclass(subject):
        for name, value in subject.__members__.items():
            if name not in members:
                members[name] = ObjectMember(name, value, class_=subject)

        superclass = subject.__mro__[1]
        for name in obj_dict:
            if name not in superclass.__dict__:
                value = safe_getattr(subject, name)
                members[name] = ObjectMember(name, value, class_=subject)

    # members in __slots__
    try:
        __slots__ = getslots(subject)
        if __slots__:
            from sphinx.ext.autodoc import SLOTSATTR

            for name, docstring in __slots__.items():
                members[name] = ObjectMember(name, SLOTSATTR, class_=subject,
                                             docstring=docstring)
    except (TypeError, ValueError):
        pass

    # other members
    for name in dir(subject):
        try:
            value = attrgetter(subject, name)
            if ismock(value):
                value = undecorate(value)

            unmangled = unmangle(subject, name)
            if unmangled and unmangled not in members:
                if name in obj_dict:
                    members[unmangled] = ObjectMember(unmangled, value, class_=subject)
                else:
                    members[unmangled] = ObjectMember(unmangled, value)
        except AttributeError:
            continue

    try:
        for cls in getmro(subject):
            # annotation only member (ex. attr: int)
            for name in getannotations(cls):
                name = unmangle(cls, name)
                if name and name not in members:
                    members[name] = ObjectMember(name, INSTANCEATTR, class_=cls)

            # append instance attributes (cf. self.attr1) if analyzer knows
            try:
                modname = safe_getattr(cls, '__module__')
                qualname = safe_getattr(cls, '__qualname__')
                analyzer = ModuleAnalyzer.for_module(modname)
                analyzer.analyze()
                for (ns, name), docstring in analyzer.attr_docs.items():
                    if ns == qualname and name not in members:
                        members[name] = ObjectMember(name, INSTANCEATTR, class_=cls,
                                                     docstring='\n'.join(docstring))
            except (AttributeError, PycodeError):
                pass
    except AttributeError:
        pass

    return members

def _getannotations(obj: Any) -> Mapping[str, Any]:
    warnings.warn('sphinx.ext.autodoc.importer._getannotations() is deprecated.',
                  RemovedInSphinx40Warning)
    return getannotations(obj)

def get_object_members(self, want_all: bool) -> Tuple[bool, ObjectMembers]:
    members = get_class_members(self.object, self.objpath, self.get_attr)
    if not want_all:
        if not self.options.members:
            return False, []  # type: ignore
        # specific members given
        selected = []
        for name in self.options.members:  # type: str
            if name in members:
                selected.append(members[name])
            else:
                logger.warning(__('missing attribute %s in object %s') %
                               (name, self.fullname), type='autodoc')
        return False, selected
    elif self.options.inherited_members:
        return False, list(members.values())
    else:
        return False, [m for m in members.values() if m.class_ == self.object]

def is_filtered_inherited_member(name: str, obj: Any) -> bool:
    if inspect.isclass(self.object):
        for cls in self.object.__mro__:
            if cls.__name__ == self.options.inherited_members and cls != self.object:
                # given member is a member of specified *super class*
                return True
            elif name in cls.__dict__:
                return False
            elif name in self.get_attr(cls, '__annotations__', {}):
                return False
            elif isinstance(obj, ObjectMember) and obj.class_ is cls:
                return False

    return False

def annotation_option(arg: Any) -> Any:
    if arg in (None, True):
        # suppress showing the representation of the object
        return SUPPRESS
    else:
        return arg

def inherited_members_option(arg: Any) -> Union[object, Set[str]]:
    """Used to convert the :members: option to auto directives."""
    if arg in (None, True):
        return 'object'
    else:
        return arg
